const p = "password"
const n = "text"
export let showPassword = (stateType = p) =>{
   if(stateType === p){
      return {
         type:"password",
         stateClass:"name active"
      }
   }
   else{
      return {
         type:"text",
         stateClass:"name"
      }
   }
}
